UPDATE stage_prompts SET config = '{"stage":2,"laneTitle":"Story Board","assemblyOrder":["masterSheetPrompt","yourDescription","universalStyle"],"universalStyle":{"key":"production_bible_universal","label":"Universal Production Bible Style","text":"GLOBAL ART DIRECTION\n\nEvery generated storyboard belongs to the same Production Bible.\n\nVisual Identity\n\u2022 Apple keynote quality\n\u2022 A24 cinematic minimalism\n\u2022 Pixar pre-production documentation\n\u2022 Weta Workshop production bible\n\u2022 Netflix concept art presentation\n\u2022 Cannes Lions advertising pitch deck\n\nGraphic Language\n\u2022 White premium presentation layout\n\u2022 Thin black divider lines\n\u2022 Spacious negative space\n\u2022 Editorial typography hierarchy\n\u2022 Soft paper texture\n\u2022 Production asset numbering\n\u2022 Revision labels\n\u2022 Version numbers\n\u2022 Project title placeholder\n\u2022 Copyright footer\n\nEvery storyboard should feel like it was created by an elite commercial art department."},"items":{"story":{"label":"Story","note":"No editable fields \u2014 the customer already decided the story, dialogue, and tone in the (now-locked) Stage 1 brief. The designer''s job here is compiling that into a Flow-ready storyboard prompt, not re-authoring a concept/tone.","content":{"geminiInstruction":"There is nothing to fill in beyond the \"prompt\" field \u2014 the brief''s \"storyboard\" field is the customer''s own already-written script and the brief''s \"tone\" field is the already-decided mood; both are locked and must be used exactly as given, never re-interpreted or summarized into a new concept. Preserve the storyboard''s actual dialogue lines, character names, and scene beats, in the same language/script they were written in \u2014 never translate them to English. Structure the \"prompt\" field as a numbered list of scenes/panels, one per beat from the script, so a designer can review and edit each individually \u2014 the number should match however many real beats the script has (do not force it to a fixed count). Carry the actual dialogue as an on-screen caption or spoken line wherever the script already has one.","fieldsSchema":[],"autoPopulate":{"note":"One Story generation drafts the skeleton of every downstream stage instead of the designer re-typing every cast member/prop/scene by hand. Each array item becomes a real item in that stage, pre-filled with this description \u2014 the designer still reviews/edits/regenerates each one individually at its own stage afterward. This is new \u2014 nothing in the app reads these fields yet; wiring it up is a ''clean the code'' task.","geminiResponseFields":[{"key":"characters","shape":"array of {name, description}","createsItemsIn":{"stage":3,"itemKey":"character"}},{"key":"properties","shape":"array of {name, description}","createsItemsIn":{"stage":3,"itemKey":"property"}},{"key":"backgrounds","shape":"array of {name, description}","createsItemsIn":{"stage":3,"itemKey":"background"}},{"key":"sounds","shape":"array of {name, description}","createsItemsIn":{"stage":3,"itemKey":"sound"}},{"key":"scenes","shape":"array of {name, summary}","createsItemsIn":{"stage":4,"itemKey":"scene"}}]}},"outputInstructions":[{"key":"master_storyboard_prompt","label":"Master Storyboard Prompt","default":true,"text":"Create a premium cinematic storyboard panel based ONLY on the storyboard description provided below.\n\nOBJECTIVE\nVisualize the described scene exactly as written.\nDo not invent additional story elements.\nMaintain the described characters, props, environment, camera angle, lens, composition, emotion, action and lighting.\n\nGenerate a production-ready storyboard suitable for a world-class advertising campaign.\n\nSTYLE\n\u2022 Hollywood commercial storyboard\n\u2022 Cannes Lions presentation quality\n\u2022 Director''s storyboard\n\u2022 Hand-drawn pencil illustration\n\u2022 Marker rendering\n\u2022 Loose confident sketch lines\n\u2022 Grayscale shading\n\u2022 Slight blue storyboard pencil accents\n\u2022 Premium beige storyboard paper\n\u2022 Elegant editorial graphic design\n\nFRAME DESIGN\n\u2022 Production Title\n\u2022 Commercial Name\n\u2022 Sequence Number\n\u2022 Scene Number\n\u2022 Shot Number\n\u2022 Frame Number\n\u2022 Shot Size\n\u2022 Camera Angle\n\u2022 Lens\n\u2022 Camera Movement\n\u2022 Aspect Ratio\n\u2022 Duration\n\u2022 Time of Day\n\u2022 Location\n\u2022 Dialogue\n\u2022 Voice Over\n\u2022 Music Cue\n\u2022 Sound Effects\n\u2022 Director Notes\n\u2022 Art Director Notes\n\u2022 Lighting Notes\n\nANNOTATIONS\n\u2022 Camera movement\n\u2022 Character movement\n\u2022 Eyeline\n\u2022 Focus direction\n\u2022 Lighting direction\n\u2022 Key prop callouts\n\u2022 Performance notes\n\u2022 Emotional beat\n\u2022 Composition notes\n\u2022 Blocking\n\u2022 Screen direction\n\nCINEMATIC QUALITY\n\u2022 Rule of thirds\n\u2022 Leading lines\n\u2022 Dynamic perspective\n\u2022 Strong silhouettes\n\u2022 Foreground / Midground / Background separation\n\u2022 Dramatic lighting\n\u2022 Motivated light source\n\u2022 Shadow direction\n\u2022 Premium production presentation\n\nCOLOR\nMostly grayscale with subtle blue storyboard pencil and light beige paper.\n\nDO NOT\n\u2022 Change the story\n\u2022 Add characters\n\u2022 Change wardrobe\n\u2022 Change props\n\u2022 Cartoonize\n\u2022 Anime\n\u2022 Comic book style\n\u2022 Photorealistic painting\n\u2022 Over-render\n\nOUTPUT\nGenerate ONE premium storyboard panel that looks like it belongs inside the production bible of a multi-million-dollar commercial."}]}}}', updated_at = datetime('now') WHERE stage = 2;
